#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[105]; scanf("%s", s);
        for (int i = 0; i < N; ++i) {
            char c = s[i];
            if (c == 'A') s[i] = 'T';
            else if (c == 'T') s[i] = 'A';
            else if (c == 'C') s[i] = 'G';
            else if (c == 'G') s[i] = 'C';
        }
        printf("%s\n", s);
    }
    return 0;
}

